import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/updating-fabric.1C0PZ95m.js";const a=JSON.parse(`{"title":"Mettre à jour Fabric","description":"Un guide pour mettre à jour Fabric pas à pas.","frontmatter":{"title":"Mettre à jour Fabric","description":"Un guide pour mettre à jour Fabric pas à pas.","authors":["IMB11","modmuss50"],"search":false,"files":[]},"headers":[],"relativePath":"fr_fr/1.20.4/players/updating-fabric.md","filePath":"versions/1.20.4/translated/fr_fr/players/updating-fabric.md","lastUpdated":1739538073000}`);var o={name:`fr_fr/1.20.4/players/updating-fabric.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Mettre à jour Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Mettre à jour Fabric”">​</a></h1><p>Ce guide explique en détail le processus de mise à jour de Fabric pour le launcher Minecraft.</p><p>Pour les lanceurs tiers, vous devriez consulter leur documentation.</p><p>La mise à jour de Fabric ressemble beaucoup à l&#39;installation de Fabric, donc certains passages seront identiques au guide <a href="./installing-fabric">Installer Fabric</a>.</p><h2 id="pourquoi-mettre-a-jour-fabric-loader" tabindex="-1">Pourquoi mettre à jour Fabric Loader ? <a class="header-anchor" href="#pourquoi-mettre-a-jour-fabric-loader" aria-label="Permalink to “Pourquoi mettre à jour Fabric Loader ?”">​</a></h2><p>De nouveaux mods peuvent nécessiter une version plus récente de Fabric Loader pour fonctionner, il est donc important de le garder à jour pour s&#39;assurer de pouvoir utiliser les mods les plus récents.</p><p>Pour mettre à jour Fabric, s&#39;assurer que les versions du jeu et de Loader correspondent, puis appuyer sur &#39;Install&#39; (Installer).</p><p><strong>Assurez-vous d&#39;avoir décoché &#39;Créer un profil&#39; en exécutant l&#39;installateur, sinon un nouveau profil sera créé, ce qui est indésirable ici.</strong></p><h2 id="_3-ouvrir-le-profil-dans-le-launcher-minecraft" tabindex="-1">3. Ouvrir le profil dans le launcher Minecraft <a class="header-anchor" href="#_3-ouvrir-le-profil-dans-le-launcher-minecraft" aria-label="Permalink to “3. Ouvrir le profil dans le launcher Minecraft”">​</a></h2><p>Une fois que l&#39;installateur a terminé, il est désormais possible d&#39;ouvrir le launcher Minecraft et d&#39;aller à l&#39;onglet &#39;Installations&#39;. Il est recommandé d&#39;aller sur votre profil Fabric et d&#39;ouvrir l&#39;écran d&#39;édition.</p><p>Remplacer la version avec la version de Fabric Loader tout juste installée et appuyer sur &#39;Sauvegarder&#39;.</p><p><img src="/assets/players/updating-fabric.png" alt="Mise à jour de la version de Fabric Loader dans le launcher Minecraft" loading="lazy"></p><h2 id="_4-et-voila" tabindex="-1">4. Et voilà ! <a class="header-anchor" href="#_4-et-voila" aria-label="Permalink to “4. Et voilà !”">​</a></h2><p>Une fois que ces étapes ont été faites, retourner à l&#39;onglet &#39;Jeu&#39;, sélectionner le profil Fabric depuis le menu déroulant dans le coin inférieur gauche et appuyer sur &#39;Jouer&#39; !</p><p>Si vous rencontrez des problèmes en suivant ce guide, vous pouvez demander de l&#39;aide dans le <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord de Fabric</a> dans le salon <code>#player-support</code>.</p>`,15)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};